                                            <div className="form-row"><div className="form-group"><label>Assistance Provided</label><input type="text" name="assistance_provided" value={displayEvent.assistance_provided} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_assistance_provided" value={displayEvent.remark_assistance_provided || ''} onChange={handleInputChange} /></div></div>
                                        </div>
                                    )}
                                </div>
                                <div className="edit-section">
                                    <div className="edit-section-header" onClick={() => toggleSection('remarks')}><h4>📝 General Remarks</h4><span>{expandedSections.remarks ? '▼' : '►'}</span></div>
                                    {expandedSections.remarks && (
                                        <div className="edit-section-content"><div className="form-group"><label>Overall Remarks</label><textarea name="remark" value={displayEvent.remark || ''} onChange={handleInputChange} rows="3" placeholder="Additional notes or instructions..." /></div></div>
