                        ) : (
                            <>
                                <div className="warning-grid">
                                    <div className="warning-grid-row header">
                                        <div className="warning-col"><div className="warning-title">TROPICAL CYCLONE WARNING SIGNAL<div className="warning-sub">(based on DOST-PAGASA Weather Updates)</div></div></div>
                                        <div className="warning-col"><div className="weather-title">GENERAL WEATHER SITUATION<div className="warning-sub">(Actual Weather situation)</div></div></div>
                                    </div>
                                    <div className="warning-grid-row content">
                                        <div className="warning-col signals-col">
                                            <div className="warning-panel">
                                                <div className="warning-signals-list">{Object.entries(displayEvent.warning_signals || {}).map(([mun, signal]) => (<div key={mun} className="signal-item"><span className="mun-name">{mun}</span><span className="signal-number">Signal No. {signal}</span></div>))}</div>
                                                {Object.keys(displayEvent.warning_signals || {}).length === 0 && <div className="no-signals">No warning signals currently in effect.</div>}
                                            </div>
                                        </div>
                                        <div className="warning-col weather-col"><div className="warning-panel weather-panel"><div className="weather-text">{selectedOffice === 'PSTO-Region-1' ? displayWeather : (displayEvent.general_weather || 'No weather data reported')}</div></div></div>
                                    </div>
                                </div>
                                <div className="effects-section"><h4>📊 EFFECTS</h4>
                                    <div className="effects-panel"><div className="effects-list">
                                        {[
                                            { label: 'Related Incidents', value: displayEvent.related_incidents, remarkField: 'remark_related_incidents' },
                                            { label: 'Casualties', value: displayEvent.casualties, remarkField: 'remark_casualties' },
                                            { label: 'Power', value: displayEvent.power_status || '—', remarkField: 'remark_power_status' },
                                            { label: 'Communication', value: displayEvent.communication_lines || '—', remarkField: 'remark_communication_lines' },
                                            { label: 'Damage', value: displayEvent.damage_facilities || '—', remarkField: 'remark_damage_facilities' },
                                            { label: 'Work Suspension', value: displayEvent.work_suspension ? 'Yes' : 'No', remarkField: 'remark_work_suspension' },
                                            { label: 'Assistance', value: displayEvent.assistance_provided || '—', remarkField: 'remark_assistance_provided' },
                                        ].map((item) => (<div key={item.label} className="effect-row"><span className="effect-label">{item.label}:</span><span className="effect-value">{item.value}</span><span className="effect-remark">{displayEvent[item.remarkField] || '-'}</span></div>))}
                                    </div></div>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );

    const TyphoonContent = () => (
        <div className="events-management">
            <div className="events-header">
                <h1>Manage Events</h1>
                <div className="header-actions">
                    <div className="search-box"><span className="search-icon">🔍</span><input type="text" placeholder="Search events..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div>
                    {canEditEvents && <button className="new-event-btn" onClick={handleOpenAddModal}>+ New Event</button>}
                </div>
            </div>
            <div className="filter-bar">
                <label>Status filter:</label>
                <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
                    <option value="all">All</option>
                    <option value="pending">Pending</option>
                    <option value="approved">Approved</option>
                    <option value="active">Active</option>
                    <option value="rejected">Rejected</option>
                    <option value="archived">Archived</option>
                </select>
            </div>
            <div className="events-table-container">
                <table className="events-table">
                    <thead>
                        <tr>
                            <th>EVENT NAME</th><th>DATE</th><th>ALERT LVL</th><th>STATUS</th><th>PROVINCES</th><th>CATEGORY</th><th>ACTIONS</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredEvents.length > 0 ? filteredEvents.map(event => (
                            <tr key={event.id} className={event.status === 'archived' ? 'archived-row' : ''}>
                                <td className="event-name">{event.name}</td>
                                <td>{event.date}</td>
                                <td><span className="alert-badge" style={{ background: getAlertColor(event.alertLevel) }}>{event.alertLevel}</span></td>
                                <td><span className="status-badge" style={{ background: getStatusColor(event.status) }}>{getEventStatusLabel(event)}</span></td>
                                <td><div className="provinces-list">{event.provinces.length === allProvinces.length ? <span className="province-tag">All PSTO Offices</span> : event.provinces.map((p, i) => <span key={i} className="province-tag">{p}</span>)}</div></td>
                                <td>{event.category || event.type || '-'}</td>
                                <td className="actions-cell">
                                    {event.deployment !== 'Deployed' && event.status === 'approved' ? (canDeployEvents ? <button className="action-btn deploy-btn" onClick={() => handleDeployEvent(event.id)}>Deploy</button> : <span className="status-badge" style={{ background: '#17a2b8' }}>Approved</span>) : event.deployment === 'Deployed' ? <span className="status-badge" style={{ background: '#198754' }}>Active</span> : <span className="status-badge" style={{ background: '#ffc107' }}>{event.status === 'pending' ? 'Awaiting Approval' : 'Draft'}</span>}
                                    <button className="action-btn view-btn" onClick={() => handleViewEvent(event)}>View Details</button>
                                    {canEditEvents && event.status === 'pending' && <button className="action-btn success" onClick={() => handleApproveEvent(event.id)}>Approve</button>}
                                    {canRejectEvents && event.status === 'pending' && <button className="action-btn danger" onClick={() => openRejectModal(event.id)}>Reject</button>}
                                </td>
                            </tr>
                        )) : (
                            <tr><td colSpan="7" style={{ textAlign: 'center', padding: '40px' }}>No events found. {canEditEvents && 'Click "+ New Event" to create one.'}</td></tr>
                        )}
                    </tbody>
                </table>
            </div>

            {showAddModal && (
                <div className="modal-overlay" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>
                    <div className="modal-content large-modal" onClick={e => e.stopPropagation()}>
                        <form onSubmit={(e) => { e.preventDefault(); handleAddEvent(); }}>
                            <div className="modal-header"><h3>{isEditingEvent ? 'Edit Event' : 'Add New Event'}</h3><button type="button" className="modal-close" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>×</button></div>
                            <div className="form-group"><label>Event Name *</label><input type="text" value={newEvent.name} onChange={(e) => setNewEvent({ ...newEvent, name: e.target.value })} required placeholder="e.g., Typhoon Rolly" /></div>
                            <div className="form-group"><label>Alert Level</label><select value={newEvent.alertLevel} onChange={(e) => setNewEvent({ ...newEvent, alertLevel: e.target.value })}><option value="">-- Select --</option><option>RED</option><option>BLUE</option><option>WHITE</option></select></div>
                            <div className="form-group"><label>Category</label><select value={newEvent.category} onChange={(e) => setNewEvent({ ...newEvent, category: e.target.value })}><option value="">-- Select --</option><option>Super Typhoon</option><option>Typhoon</option><option>Severe Tropical Storm</option><option>Tropical Storm</option><option>Tropical Depression</option></select></div>
                            <div className="datetime-row"><div className="datetime-group"><label>Start Date/Time</label><input type="datetime-local" value={newEvent.startDateTime} onChange={(e) => setNewEvent({ ...newEvent, startDateTime: e.target.value })} /></div><div className="datetime-group"><label>End Date/Time</label><input type="datetime-local" value={newEvent.endDateTime} onChange={(e) => setNewEvent({ ...newEvent, endDateTime: e.target.value })} /></div></div>
                            <div className="form-group"><label>Provinces</label><div className="scope-grid">{allProvinces.map(p => (<button type="button" key={p} className={`scope-item ${newEvent.provinces.includes(p) ? 'selected' : ''}`} onClick={() => { const selected = newEvent.provinces.includes(p); setNewEvent({ ...newEvent, provinces: selected ? newEvent.provinces.filter(x => x !== p) : [...newEvent.provinces, p], sendToAllUsers: false }); }}>{p}</button>))}<label><input type="checkbox" checked={newEvent.sendToAllUsers} onChange={(e) => setNewEvent({ ...newEvent, sendToAllUsers: e.target.checked, provinces: e.target.checked ? allProvinces : newEvent.provinces })} /> Send to all offices</label></div></div>
                            <div className="form-group"><label>Track Positions</label><textarea value={newEvent.trackPositions} onChange={(e) => setNewEvent({ ...newEvent, trackPositions: e.target.value })} placeholder="e.g., 13.0N 121.2E → 13.8N 122.1E" /></div>
                            <div className="form-group"><label>Intensity</label><input type="text" value={newEvent.intensity} onChange={(e) => setNewEvent({ ...newEvent, intensity: e.target.value })} placeholder="e.g., 95 kph / 52 kt" /></div>
                            <div className="form-group"><label>Report Link (URL)</label><input type="url" value={newEvent.reportLink} onChange={(e) => setNewEvent({ ...newEvent, reportLink: e.target.value })} placeholder="https://..." /></div>
                            <div className="form-group"><label>Event Image</label><input type="file" accept="image/*" onChange={(e) => { const file = e.target.files[0]; if (file) { const reader = new FileReader(); reader.onload = () => setNewEvent({ ...newEvent, imageUrl: reader.result }); reader.readAsDataURL(file); } }} /></div>
                            {newEvent.imageUrl && <img src={newEvent.imageUrl} alt="Preview" className="event-image-preview" />}
                            <div className="modal-buttons"><button type="submit" className="success">{isEditingEvent ? 'Save Changes' : 'Create Event'}</button><button type="button" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>Cancel</button></div>
                        </form>
                    </div>
                </div>
            )}

            {showDetailsModal && selectedEvent && (
                <div className="modal-overlay" onClick={handleCloseDetailsModal}>
                    <div className="modal-content event-details-modal" onClick={e => e.stopPropagation()}>
                        <div className="details-header"><div className="details-title">{selectedEvent.name}</div><button className="modal-close" onClick={handleCloseDetailsModal}>×</button></div>
                        <div className="detail-section"><div className="detail-section-title">TROPICAL CYCLONE PRELIMINARY REPORT</div><div className="report-panel">{isEditingReportLink ? (<div className="report-edit-group"><input type="url" value={reportLinkInput} onChange={(e) => setReportLinkInput(e.target.value)} /><button className="success" onClick={handleSaveReportLink}>Save</button><button onClick={() => setIsEditingReportLink(false)}>Cancel</button></div>) : (<div className="report-display-group">{selectedEvent.reportLink ? <a href={selectedEvent.reportLink} target="_blank" rel="noopener noreferrer">View Report</a> : <span>No report link</span>}{canEditEvents && <button className="edit-link-btn" onClick={() => { setReportLinkInput(selectedEvent.reportLink || ''); setIsEditingReportLink(true); }}>✏️ Add/Edit Link</button>}</div>)}</div></div>
                        <div className="details-grid"><div className="detail-box"><div className="detail-label">Category</div><div className="detail-value">{selectedEvent.category || selectedEvent.type}</div></div><div className="detail-box"><div className="detail-label">Alert Level</div><div className="detail-value">{selectedEvent.alertLevel}</div></div><div className="detail-box"><div className="detail-label">Start Date</div><div className="detail-value">{selectedEvent.startDateTime ? new Date(selectedEvent.startDateTime).toLocaleString() : selectedEvent.date}</div></div><div className="detail-box"><div className="detail-label">End Date</div><div className="detail-value">{selectedEvent.endDateTime ? new Date(selectedEvent.endDateTime).toLocaleString() : 'Ongoing'}</div></div></div>
                        <div className="detail-section"><div className="detail-section-title">Deployment Scope</div><div className="scope-tags">{selectedEvent.provinces.map((p, i) => <span key={i} className="scope-tag">{p}</span>)}</div></div>
                        <div className="detail-section"><div className="detail-section-title">Track & Intensity</div><div className="summary-panel"><p><strong>Positions:</strong> {selectedEvent.trackPositions || 'Not specified'}</p><p><strong>Intensity:</strong> {selectedEvent.intensity || 'Not specified'}</p></div></div>
                        {selectedEvent.imageUrl && <div className="detail-section"><img src={selectedEvent.imageUrl} alt="Event" className="event-image-preview" onClick={() => openImageModal(selectedEvent.imageUrl)} /></div>}
                        {selectedEvent.rejectionReason && <div className="rejection-reason"><strong>Rejection reason:</strong> {selectedEvent.rejectionReason}</div>}
                        <div className="modal-buttons details-actions">
                            {canEditEvents && <><button className="danger" onClick={() => handleDeleteEvent(selectedEvent.id)}>Delete</button><button className="success" onClick={() => handleEditEvent(selectedEvent)}>Edit</button></>}
                            <button onClick={handleCloseDetailsModal}>Close</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );

    const PendingReportsContent = () => {
        const pending = pendingReports.filter(r => r.status === 'pending');
        return (
            <div className="events-management">
                <div className="events-header"><h1>Pending PSTO Reports</h1></div>
                <div className="events-subtitle">Review and approve reports submitted by PSTO offices</div>
                <div className="events-table-container">
                    <table className="events-table">
                        <thead><tr><th>Office</th><th>Submitted By</th><th>Submitted At</th><th>Status</th><th>Actions</th></tr></thead>
                        <tbody>
                            {pending.map(report => (
                                <tr key={report.id}>
                                    <td>{report.office}</td>
                                    <td>{report.submittedBy}</td>
                                    <td>{new Date(report.submittedAt).toLocaleString()}</td>
                                    <td><span className="status-badge" style={{ background: '#ffc107' }}>Pending</span></td>
                                    <td className="actions-cell">
                                        <button className="success" onClick={() => approveReport(report.id)}>Approve</button>
                                        <button className="danger" onClick={() => openRejectReportModal(report)}>Reject</button>
                                        <button className="view-btn" onClick={() => { setSelectedReport(report); setShowReportReviewModal(true); }}>Review</button>
                                    </td>
                                </tr>
                            ))}
                            {pending.length === 0 && <tr><td colSpan="5" style={{ textAlign: 'center', padding: '40px' }}>No pending reports. If no typhoon is active, users can submit reports when a typhoon is declared.</td></tr>}
                        </tbody>
                    </table>
                </div>
            </div>
        );
    };

    const ReportReviewModal = () => {
        if (!selectedReport) return null;
        const original = officesData[selectedReport.office];
        const submitted = selectedReport.data;
        const diffKeys = [];
        const allKeys = new Set([...Object.keys(original), ...Object.keys(submitted)]);
        allKeys.forEach(key => {
            if (JSON.stringify(original[key]) !== JSON.stringify(submitted[key])) {
                diffKeys.push(key);
            }
        });
        return (
            <div className="modal-overlay" onClick={() => setShowReportReviewModal(false)}>
                <div className="modal-content large-modal" onClick={e => e.stopPropagation()}>
                    <div className="modal-header"><h3>Review Report - {selectedReport.office}</h3><button className="modal-close" onClick={() => setShowReportReviewModal(false)}>×</button></div>
                    <div><strong>Submitted by:</strong> {selectedReport.submittedBy} on {new Date(selectedReport.submittedAt).toLocaleString()}</div>
                    <div className="diff-section">
                        <h4>Changes (original → submitted)</h4>
                        {diffKeys.length === 0 && <p>No changes detected.</p>}
                        {diffKeys.map(key => (
                            <div key={key} className="diff-row">
                                <strong>{key}:</strong><br />
                                <span className="diff-old">Original: {JSON.stringify(original[key])}</span><br />
                                <span className="diff-new">Submitted: {JSON.stringify(submitted[key])}</span>
                            </div>
                        ))}
                    </div>
                    {selectedReport.status === 'rejected' && <div className="rejection-reason"><strong>Rejection reason:</strong> {selectedReport.remarks}</div>}
                    {selectedReport.status === 'pending' && (
                        <div className="modal-buttons">
                            <button className="success" onClick={() => { approveReport(selectedReport.id); setShowReportReviewModal(false); }}>Approve</button>
                            <button className="danger" onClick={() => { setShowReportReviewModal(false); openRejectReportModal(selectedReport); }}>Reject</button>
                            <button onClick={() => setShowReportReviewModal(false)}>Close</button>
                        </div>
                    )}
                    {selectedReport.status !== 'pending' && <button onClick={() => setShowReportReviewModal(false)}>Close</button>}
                </div>
            </div>
        );
    };

    const SubmitReportModal = () => {
        if (!reportFormData) return null;
        return (
            <div className="modal-overlay" onClick={() => setShowReportModal(false)}>
                <div className="modal-content large-modal" onClick={e => e.stopPropagation()}>
                    <div className="modal-header"><h3>Submit Report for {selectedOffice}</h3><button className="modal-close" onClick={() => setShowReportModal(false)}>×</button></div>
                    <div className="form-section"><label>Warning Signals</label>
                        {reportFormData.municipalities.map(mun => (
                            <div key={mun} className="signal-edit-row"><span>{mun}</span><select value={reportFormData.warning_signals[mun] || 0} onChange={(e) => handleReportSignalChange(mun, e.target.value)}><option value={0}>No Signal</option><option value={1}>#1</option><option value={2}>#2</option><option value={3}>#3</option><option value={4}>#4</option><option value={5}>#5</option></select><button className="remove-mun-btn" onClick={() => handleReportRemoveMunicipality(mun)}>🗑️</button></div>
                        ))}
                        <div className="add-municipality-row"><input placeholder="New municipality" value={newMunicipality} onChange={(e) => setNewMunicipality(e.target.value)} /><select value={newSignal} onChange={(e) => setNewSignal(parseInt(e.target.value))}><option>#1</option><option>#2</option><option>#3</option><option>#4</option><option>#5</option></select><button className="add-mun-btn" onClick={handleReportAddMunicipality}>+ Add</button></div>
                    </div>
                    <div className="form-group"><label>General Weather</label><input type="text" value={reportFormData.general_weather} onChange={(e) => handleReportFieldChange('general_weather', e.target.value)} /></div>
                    <div className="form-row"><div className="form-group"><label>Related Incidents</label><input type="number" value={reportFormData.related_incidents} onChange={(e) => handleReportFieldChange('related_incidents', parseInt(e.target.value) || 0)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_related_incidents || ''} onChange={(e) => handleReportFieldChange('remark_related_incidents', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group"><label>Casualties</label><input type="number" value={reportFormData.casualties} onChange={(e) => handleReportFieldChange('casualties', parseInt(e.target.value) || 0)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_casualties || ''} onChange={(e) => handleReportFieldChange('remark_casualties', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group"><label>Power Status</label><input type="text" value={reportFormData.power_status} onChange={(e) => handleReportFieldChange('power_status', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_power_status || ''} onChange={(e) => handleReportFieldChange('remark_power_status', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group"><label>Communication Lines</label><input type="text" value={reportFormData.communication_lines} onChange={(e) => handleReportFieldChange('communication_lines', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_communication_lines || ''} onChange={(e) => handleReportFieldChange('remark_communication_lines', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group"><label>Damage to Facilities</label><input type="text" value={reportFormData.damage_facilities} onChange={(e) => handleReportFieldChange('damage_facilities', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_damage_facilities || ''} onChange={(e) => handleReportFieldChange('remark_damage_facilities', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group checkbox-group"><label><input type="checkbox" checked={reportFormData.work_suspension} onChange={(e) => handleReportFieldChange('work_suspension', e.target.checked)} /> Work Suspension</label></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_work_suspension || ''} onChange={(e) => handleReportFieldChange('remark_work_suspension', e.target.value)} /></div></div>
                    <div className="form-row"><div className="form-group"><label>Assistance Provided</label><input type="text" value={reportFormData.assistance_provided} onChange={(e) => handleReportFieldChange('assistance_provided', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_assistance_provided || ''} onChange={(e) => handleReportFieldChange('remark_assistance_provided', e.target.value)} /></div></div>
                    <div className="modal-buttons"><button className="success" onClick={submitReport}>Submit for Approval</button><button onClick={() => setShowReportModal(false)}>Cancel</button></div>
                </div>
            </div>
        );
    };

    const UsersContent = () => {
        const filteredUsers = users.filter(u => u.name.toLowerCase().includes(userSearchTerm.toLowerCase()) || u.email.toLowerCase().includes(userSearchTerm.toLowerCase()) || u.role.toLowerCase().includes(userSearchTerm.toLowerCase()));
        return (
            <div className="events-management users-management">
                <div className="events-header">
                    <h1>User Management</h1>
                    <div className="header-actions">
                        <div className="search-box"><span className="search-icon">🔍</span><input type="text" placeholder="Search users..." value={userSearchTerm} onChange={(e) => setUserSearchTerm(e.target.value)} /></div>
                        <button className="new-event-btn" onClick={() => { setUserForm({ id: null, name: '', email: '', office: selectedOffice, role: 'USER', status: 'Active', password: '' }); setIsEditingUser(false); setShowUserModal(true); }}>+ New User</button>
                    </div>
                </div>
                <div className="events-table-container">
                    <table className="events-table users-table">
                        <thead>
                            <tr><th>Name</th><th>Email</th><th>Office</th><th>Role</th><th>Status</th><th>Actions</th></tr>
                        </thead>
                        <tbody>
                            {filteredUsers.map(user => (
                                <tr key={user.id}>
                                    <td>{user.name}</td>
                                    <td>{user.email}</td>
                                    <td>{user.office}</td>
                                    <td><span className="role-badge">{user.role}</span></td>
                                    <td>{user.status}</td>
                                    <td className="actions-cell">
                                        <button className="view-btn" onClick={() => { setUserForm(user); setIsEditingUser(true); setShowUserModal(true); }}>Edit</button>
                                        <button className="deploy-btn" onClick={() => handleDeleteUser(user.id)}>Delete</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                {showUserModal && (
                    <div className="modal-overlay" onClick={() => setShowUserModal(false)}>
                        <div className="modal-content" onClick={e => e.stopPropagation()}>
                            <div className="modal-header"><h3>{isEditingUser ? 'Edit User' : 'Create User'}</h3><button className="modal-close" onClick={() => setShowUserModal(false)}>×</button></div>
                            <div className="form-group"><label>Name</label><input type="text" value={userForm.name} onChange={(e) => setUserForm({ ...userForm, name: e.target.value })} /></div>
                            <div className="form-group"><label>Email</label><input type="email" value={userForm.email} onChange={(e) => setUserForm({ ...userForm, email: e.target.value })} /></div>
                            <div className="form-group"><label>Office</label><select value={userForm.office} onChange={(e) => setUserForm({ ...userForm, office: e.target.value })}>{['PSTO-Ilocos Norte', 'PSTO-Ilocos Sur', 'PSTO-La Union', 'PSTO-Pangasinan'].map(off => <option key={off}>{off}</option>)}</select></div>
                            <div className="form-group"><label>Password {isEditingUser && '(leave blank to keep current)'}</label><input type="password" value={userForm.password} onChange={(e) => setUserForm({ ...userForm, password: e.target.value })} /></div>
                            <div className="form-group"><label>Role</label><select value={userForm.role} onChange={(e) => setUserForm({ ...userForm, role: e.target.value })}><option value="SADMIN">SADMIN</option><option value="ADMIN">ADMIN</option><option value="USER">USER</option></select></div>
                            <div className="form-group"><label>Status</label><select value={userForm.status} onChange={(e) => setUserForm({ ...userForm, status: e.target.value })}><option>Active</option><option>Inactive</option></select></div>
                            <div className="modal-buttons"><button className="success" onClick={handleSaveUser}>{isEditingUser ? 'Save' : 'Create'}</button><button onClick={() => setShowUserModal(false)}>Cancel</button></div>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const NotificationsContent = () => {
        return (
            <div className="events-management">
                <div className="events-header">
                    <h1>Notifications {unreadCount > 0 && `(${unreadCount} new)`}</h1>
                    <div className="header-actions"><button className="new-event-btn" onClick={clearAllNotifications}>Clear All</button></div>
                </div>
                <div className="events-subtitle">System events, report updates, and alerts</div>
                <div className="notifications-list">
                    {notifications.length === 0 ? (
                        <div className="no-notifications">No notifications yet.</div>
                    ) : (
                        notifications.map(notif => (
                            <div key={notif.id} className={`notification-item ${!notif.read ? 'unread' : ''} ${notif.type}`} onClick={() => markNotificationRead(notif.id)}>
                                <div className="notification-header"><span className="notification-title">{notif.title}</span><span className="notification-time">{new Date(notif.timestamp).toLocaleString()}</span></div>
                                <div className="notification-message">{notif.message}</div>
                            </div>
                        ))
                    )}
                </div>
            </div>
        );
    };

    // ----------------------------- MAIN RENDER -----------------------------
    return (
        <div className="dashboard-container">
            <div className="sidebar-new">
                <div className="sidebar-logo"><h2>DOST Region 1</h2><p>Disaster Management</p></div>
                <nav className="sidebar-nav">
                    <div className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}><span className="nav-icon">📊</span><span>Dashboard</span></div>
                    <div className={`nav-item ${activeMenu === 'typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('typhoon')}><span className="nav-icon">🌊</span><span>Typhoon</span></div>
                    <div className={`nav-item ${activeMenu === 'live-typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('live-typhoon')}><span className="nav-icon">🗺️</span><span>Live Typhoon (Panahon)</span></div>
                    <div className={`nav-item ${activeMenu === 'notifications' ? 'active' : ''}`} onClick={() => setActiveMenu('notifications')}><span className="nav-icon">🔔</span><span>Notifications {unreadCount > 0 && `(${unreadCount})`}</span></div>
                    {canApproveReports && <div className={`nav-item ${activeMenu === 'pending-reports' ? 'active' : ''}`} onClick={() => setActiveMenu('pending-reports')}><span className="nav-icon">📋</span><span>Pending Reports</span></div>}
                    {canManageUsers && <div className={`nav-item ${activeMenu === 'users' ? 'active' : ''}`} onClick={() => setActiveMenu('users')}><span className="nav-icon">👥</span><span>Users</span></div>}
                </nav>
                <div className="sidebar-footer">
                    <div className="user-info"><div className="user-greeting">Hello, {currentUser?.name || 'Admin'}</div><div className="user-role">{isSuperAdmin ? 'SUPER ADMIN' : (isAdmin ? 'ADMIN' : 'USER')}</div></div>
                    <div className="user-actions"><div className="action-item logout" onClick={onLogout}>🚪 Logout</div></div>
                </div>
            </div>
            <div className="main-content">
                {isSuperAdmin && (
                    <div className="admin-toolbar">
                        <button onClick={resetToDefaultData}>Reset to Default Data</button>
                        <button onClick={exportData}>Export Data</button>
                        <label className="import-btn"><input type="file" onChange={importData} style={{ display: 'none' }} />Import Data</label>
                    </div>
                )}
                {activeMenu === 'dashboard' && <DashboardContent />}
                {activeMenu === 'typhoon' && <TyphoonContent />}
                {activeMenu === 'live-typhoon' && (
                    <div className="forecast-section card">
                        <h1>Live Typhoon (Panahon)</h1>
                        <div className="windy-embed-container"><iframe title="Panahon" src="https://www.panahon.gov.ph/" frameBorder="0" allowFullScreen /></div>
                    </div>
                )}
                {activeMenu === 'notifications' && <NotificationsContent />}
                {activeMenu === 'pending-reports' && canApproveReports && <PendingReportsContent />}
                {activeMenu === 'users' && canManageUsers && <UsersContent />}
            </div>
            {showReportModal && <SubmitReportModal />}
            {showReportReviewModal && <ReportReviewModal />}
            {showRejectModal && (
                <div className="modal-overlay" onClick={() => setShowRejectModal(false)}>
                    <div className="modal-content">
                        <h3>Reject Event</h3>
                        <textarea className="reject-reason-textarea" placeholder="Provide reason for rejection..." value={rejectReason} onChange={(e) => setRejectReason(e.target.value)} />
                        <div className="modal-buttons"><button className="danger" onClick={confirmRejectEvent}>Confirm Rejection</button><button onClick={() => setShowRejectModal(false)}>Cancel</button></div>
                    </div>
                </div>
            )}
            {showImageModal && imageModalSrc && (
                <div className="modal-overlay" onClick={closeImageModal}>
                    <div className="modal-content image-modal-content" onClick={e => e.stopPropagation()}>
                        <button className="modal-close" onClick={closeImageModal}>×</button>
                        <img src={imageModalSrc} alt="Enlarged" className="image-modal-img" />
                    </div>
                </div>
            )}
        </div>
    );
};

export default Dashboard;
